sql:
SELECT cultivar, bottle_size
FROM wines
WHERE year > 2015;

SELECT COUNT(wine_id) AS total_wines
FROM wines
WHERE year = 2019;

SELECT wine_id, cultivar, year, region, winemaker_id, cultivar_variety, vineyard, bottle_size, bottle_count, aging_time, sustainability_certification
FROM wines
WHERE aging_time = (
    SELECT MAX(aging_time) FROM wines
)
ORDER BY aging_time DESC;

SELECT name 
FROM winemakers 
WHERE experience_years > 10;

SELECT DISTINCT cultivar
FROM wines
ORDER BY cultivar ASC;

SELECT AVG(bottle_count) AS average_bottle_count
FROM wines
WHERE sustainability_certification = 'Organic';

SELECT cultivar
FROM wines
WHERE region = 'California';

SELECT temperature, humidity, storage_time
FROM storage_conditions
WHERE storage_location = 'Cellar A';

SELECT COUNT(DISTINCT cultivar_variety) AS unique_varietals, year AS vintage, region
FROM wines
GROUP BY year, region;

SELECT AVG(qa.score) AS average_quality_score
FROM wines w
JOIN quality_assessments qa ON w.wine_id = qa.wine_id;
